exports.notify = async (req, res) => {
  try {
    if (req.method !== 'POST') return json(res, 405, { ok: false, error: 'Method Not Allowed' });
    if (!validateAuth(req)) return json(res, 401, { ok: false, error: 'Unauthorized' });

    const body = readBody(req);

    const emailPayload = body.email;
    const smsPayload = body.sms;

    if (!emailPayload && !smsPayload) {
      return json(res, 400, { ok: false, error: 'Provide at least one of: { email, sms }' });
    }

    const results = {};
    const tasks = [];

    if (emailPayload) {
      tasks.push(
        sendEmail(emailPayload)
          .then((r) => { results.email = r; })
          .catch((e) => { results.email = { ok: false, provider: 'sendgrid', error: e.message }; })
      );
    }

    if (smsPayload) {
      tasks.push(
        sendSms(smsPayload)
          .then((r) => { results.sms = r; })
          .catch((e) => { results.sms = { ok: false, provider: 'twilio', error: e.message }; })
      );
    }

    await Promise.all(tasks);

    const ok = Object.values(results).some((r) => r && r.ok);
    const status = ok ? 200 : 502;

    return json(res, status, { ok, results });
  } catch (err) {
    const safe = { message: err && err.message ? err.message : String(err) };
    const debug = process.env.NODE_ENV === 'development' ? { stack: err && err.stack } : undefined;
    return json(res, 500, { ok: false, error: safe.message, ...(debug ? debug : {}) });
  }
};

